form:Form.form:Scripts:
		var myMENU;

function onLoad() 
{
	var proxy = GetProxy();
	myMENU=new nomadDOM(proxy.FileService().LoadFile("Menus", proxy.GetCfgResource("start-form-menu-portal")));


	switch(Ctrl("main").GetMode().toUpperCase())
	{
		case "HOME":   Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("0"); break;
		case "FAV":    Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("1"); break;
		case "PER":    Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("2"); break;
		case "CLOSE":  Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("3"); break;
		case "ANONIMO": 
		break;
	}
}              

function ChangeModule(OBJ)
{              
	if (Ctrl("main").GetMode().toUpperCase()!=OBJ.values[parseInt(OBJ.GetXValue(),10)].image.toUpperCase())
	{
		g_strFormMode=OBJ.values[parseInt(OBJ.GetXValue(),10)].image.toUpperCase();

		if (g_strFormMode=="CLOSE") 
		{
			if (confirm("Esta seguro que quiere salir?"))
				getFormVisualize(g_strFormClass, "ANONIMO");
			else
			{
				switch(Ctrl("main").GetMode().toUpperCase())
				{
					case "HOME":   Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("0"); break;
					case "FAV":    Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("1"); break;
					case "PER":    Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("2"); break;
					case "CLOSE":  Ctrl("Modulos").SetArray(myMENU.Child); Ctrl("Modulos").SetCValue("3"); break;
					case "ANONIMO": 
					break;
				}
			}

		} else 
			getFormVisualize(g_strFormClass, g_strFormMode);

		return;
	} 

	if (OBJ.values[parseInt(OBJ.GetXValue(),10)].Child.length!=0)
	{
		if (Ctrl("Nivel2")) Ctrl("Nivel2").SetArray(OBJ.values[parseInt(OBJ.GetXValue(),10)].Child[0].Child);
	}
}

function CallObject(OBJ) {                     
  CallMenu("../../..", OBJ.LastAction);
}

function CallMenu(relative, OBJ) {                     
  var act=OBJ.split(":");

  switch(act[0].toUpperCase())
  {
  	case "RPT": 
			window.open(relative+"/ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file="+act[1], '', 'channelmode=no,directories=no,fullscreen=no,location=no,menubar=no,resizable=yes,scrollbars=yes,status=no,titlebar=no,toolbar=no,left=0,top=0,width='+(screen.availWidth-12)+',height='+(screen.availHeight-60));
  	break;

  	default: 
  	break;
  }

}

function HOME_EDIT()
{
	Ctrl("HOME").Mode="EDIT";
	Ctrl("HOME").SyncHTML();
}

function FAV_EDIT()
{
	Ctrl("FAV").Mode="EDIT";
	Ctrl("FAV").SyncHTML();
}

function fnLOGIN()
{                
	window.setTimeout('getFormVisualize(g_strFormClass, "FAV");',100);
}
